export namespace cfg {
export class GDLanguage {
    private _dataMap: Map<string, cfg.GDLanguageData>
    private _dataList: cfg.GDLanguageData[]
    constructor(_json_: any) {
        this._dataMap = new Map<string, cfg.GDLanguageData>()
        this._dataList = []
        for(var _json2_ of _json_) {
            let _v: cfg.GDLanguageData
            _v = new cfg.GDLanguageData(_json2_)
            this._dataList.push(_v)
            this._dataMap.set(_v.id, _v)
        }
    }

    getDataMap(): Map<string, cfg.GDLanguageData> { return this._dataMap; }
    getDataList(): cfg.GDLanguageData[] { return this._dataList; }

    get(key: string): cfg.GDLanguageData | undefined { return this._dataMap.get(key); }

    resolve(tables:Tables) {
        for(let  data of this._dataList)
        {
            data.resolve(tables)
        }
    }

}
}


